func searchTasks(c *gin.Context) {
    q := c.Query("description")
    rows, _ := db.Query(fmt.Sprintf("SELECT * FROM tasks WHERE description LIKE '%%%s%%'", q))
    defer rows.Close()
    var results []Task
    for rows.Next() {
        var item Task
        rows.Scan(&item.ID, &item.Description)
        results = append(results, item)
    }
    c.JSON(200, results)
}

