func searchNamespaces(c *gin.Context) {
    q := c.Query("name")
    rows, _ := db.Query(fmt.Sprintf("SELECT * FROM namespace WHERE name LIKE '%%%s%%'", q))
    defer rows.Close()
    var results []Namespace
    for rows.Next() {
        var item Namespace
        rows.Scan(&item.ID, &item.Name)
        results = append(results, item)
    }
    c.JSON(200, results)
}

