app.get('/api/ingredient_items', authenticate, async (req, res) => {
    const page = parseInt(req.query.page) || 1;
    const limit = Math.min(parseInt(req.query.limit) || 20, 100);
    const items = await Ingredient.find({ owner: req.user.id })
        .skip((page - 1) * limit)
        .limit(limit)
        .lean();
    const total = await Ingredient.countDocuments({ owner: req.user.id });
    res.json({ items, total, page });
});

