@RestController
@RequestMapping("/api/debit")
@PreAuthorize("isAuthenticated()")
public class DebitController {
    @GetMapping
    public Page<DebitDTO> list(@AuthenticationPrincipal User user, Pageable pageable) {
        return repo.findByOwnerId(user.getId(), pageable).map(mapper::toDto);
    }

    @PostMapping
    public ResponseEntity<DebitDTO> create(@RequestBody @Valid DebitCreateDTO dto, @AuthenticationPrincipal User user) {
        Debit entity = mapper.toEntity(dto);
        entity.setOwnerId(user.getId());
        return ResponseEntity.status(201).body(mapper.toDto(repo.save(entity)));
    }
}

