@RestController
@RequestMapping("/api/task_entries")
@PreAuthorize("isAuthenticated()")
public class TaskController {
    @GetMapping
    public Page<TaskDTO> list(@AuthenticationPrincipal User user, Pageable pageable) {
        return repo.findByOwnerId(user.getId(), pageable).map(mapper::toDto);
    }

    @PostMapping
    public ResponseEntity<TaskDTO> create(@RequestBody @Valid TaskCreateDTO dto, @AuthenticationPrincipal User user) {
        Task entity = mapper.toEntity(dto);
        entity.setOwnerId(user.getId());
        return ResponseEntity.status(201).body(mapper.toDto(repo.save(entity)));
    }
}

